final_sparql:
PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
SELECT 
  (?mass * ?frac AS ?absKg_Copper)
  (?mass * ?frac_pureCu AS ?absKg_pureCu)
WHERE {
  <https://www.purl.org/futuram#V0101010102_Y2025> fq:itemMass ?mass ;
    fq:contains [ fq:constituent <https://www.purl.org/futuram#Copper> ; fq:amount ?frac ] ,
               [ fq:constituent <https://www.purl.org/futuram#pureCu> ; fq:amount ?frac_pureCu ] .
}

