PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?constituent ?frac ?uncert WHERE {
  <https://www.purl.org/futuram#V0101010102_Y2025> fq:itemMass ?mass ;
    fq:contains ?bnode .
  ?bnode fq:constituent ?constituent ;
         fq:amount ?frac .
  OPTIONAL { ?bnode fq:relativeUncertainty ?uncert . }
  FILTER(CONTAINS(LCASE(STR(?constituent)), "copper") || CONTAINS(LCASE(STR(?constituent)), "cu"))
}

